    {
      "quote_id": "Q004",
      "block_id": "B006",
      "text": "Thoma Bravo"
    },
    {
      "quote_id": "Q005",
      "block_id": "B030",
      "text": "Sponsor A"
    },
    {
      "quote_id": "Q006",
